mapper.sql:
AND (


            (
                g.entity_type = 'customer'




                        AND g.owner_user_id IN

                            #{userId}



                        AND 1 = 0


            ) OR


            (
                g.entity_type = 'contact'




                        AND g.customer_owner_id IN

                            #{userId}



                        AND 1 = 0


            ) OR


            (
                g.entity_type = 'relation'
                AND g.owner_user_id = #{query.currentUserId}
            ) OR


            (
                g.entity_type = 'product'




                        AND g.owner_user_id IN

                            #{userId}



                        AND 1 = 0


            ) OR


            (
                g.entity_type = 'task'
                AND (g.owner_user_id IS NULL OR g.owner_user_id = #{query.currentUserId})




                        AND g.assigned_user_id IN

                            #{userId}



                        AND 1 = 0


            ) OR


            (
                g.entity_type = 'schedule'
                AND (
                    (
                        g.owner_user_id IS NULL
                        AND (


                                    1 = 1


                                    g.create_user_id IN

                                        #{userId}



                                    1 = 0


                            OR (',' || COALESCE(g.participant_user_ids, '') || ',') LIKE ('%,' || CAST(#{query.currentUserId} AS TEXT) || ',%')
                        )
                    )
                    OR (g.owner_user_id = #{query.currentUserId})
                )
            ) OR


            (
                g.entity_type = 'knowledge'
                AND (g.owner_user_id IS NULL OR g.owner_user_id = #{query.currentUserId})
                AND (
                    (
                        g.customer_id IS NOT NULL


                                AND g.customer_owner_id IS NOT NULL


                                AND g.customer_owner_id IN

                                    #{userId}



                                AND 1 = 0


                    )
                    OR
                    (
                        g.customer_id IS NULL


                                AND g.upload_user_id IS NOT NULL


                                AND g.upload_user_id IN

                                    #{userId}



                                AND 1 = 0


                    )
                )
            ) OR


)

WHERE 1 = 1
AND g.entity_type = #{query.entityType}
AND ( LOWER(COALESCE(g.search_text, '')) LIKE CONCAT('%', LOWER(CAST(#{query.keyword,jdbcType=VARCHAR} AS TEXT)), '%') OR LOWER(COALESCE(g.title, '')) LIKE CONCAT('%', LOWER(CAST(#{query.keyword,jdbcType=VARCHAR} AS TEXT)), '%') OR LOWER(COALESCE(g.subtitle, '')) LIKE CONCAT('%', LOWER(CAST(#{query.keyword,jdbcType=VARCHAR} AS TEXT)), '%') )

mapper.delete:
DELETE FROM crm_global_search_index
WHERE entity_type = #{entityType}
  AND entity_id = #{entityId}

DELETE FROM crm_global_search_index
WHERE customer_id = #{customerId}
  AND entity_type = #{entityType}
